1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_RATE = 0.3;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const LOYALTY_RATE = 0.2;
8	const FOLLOW_UP_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
14	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
15	
16	const BASE_PREMIUM: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const INSURANCE_VALUE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	type Item = {
35	  type: string;
36	  material?: string;
37	  enchantment?: number;
38	  cursed?: boolean;
39	};
40	type Damage = { itemType: string; amount: number };
41	type Incident = { cause: string; damages: Damage[] };
42	type QuoteStep = { op: "quote"; items: Item[] };
43	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
44	type Step = QuoteStep | ClaimStep;
45	type Customer = { yearsWithMHPCO: number };
46	type Scenario = { customer: Customer; steps: Step[] };
47	type QuoteResult = { premium: number };
48	type ClaimResult = { payout: number; remainingCap: number };
49	type StepResult = QuoteResult | ClaimResult;
50	type ScenarioOutput = { results: StepResult[] };
51	
52	type Policy = { items: Item[]; remainingCap: number };
53	
54	const countBy = <T>(values: T[], keyOf: (value: T) => string): Map<string, number> => {
55	  const counts = new Map<string, number>();
56	  for (const value of values) {
57	    const key = keyOf(value);
58	    counts.set(key, (counts.get(key) ?? 0) + 1);
59	  }
60	  return counts;
61	};
62	
63	const groupCountsByType = (items: Item[]): Map<string, number> =>
64	  countBy(items, (item) => item.type);
65	
66	const basePremiumForGroup = (type: string, count: number): number => {
67	  if (!(type in BASE_PREMIUM)) {
68	    throw new Error(`unknown item type: ${type}`);
69	  }
70	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
71	  return count * BASE_PREMIUM[type];
72	};
73	
74	const basePremiumFor = (items: Item[]): number =>
75	  Array.from(groupCountsByType(items)).reduce(
76	    (total, [type, count]) => total + basePremiumForGroup(type, count),
77	    0,
78	  );
79	
80	const curseSurchargeFor = (item: Item): number =>
81	  item.cursed ? BASE_PREMIUM[item.type] * CURSE_RATE : 0;
82	
83	const highEnchantmentSurchargeFor = (item: Item): number =>
84	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
85	    ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_RATE
86	    : 0;
87	
88	const ITEM_SURCHARGES: Array<(item: Item) => number> = [
89	  curseSurchargeFor,
90	  highEnchantmentSurchargeFor,
91	];
92	
93	const surchargesForItem = (item: Item): number =>
94	  ITEM_SURCHARGES.reduce((sum, surcharge) => sum + surcharge(item), 0);
95	
96	const itemSurchargesFor = (items: Item[]): number =>
97	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
98	
99	const firstInsuranceSurchargeFor = (basePremium: number): number =>
100	  basePremium * FIRST_INSURANCE_RATE;
101	
102	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
103	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
104	    ? basePremium * LOYALTY_RATE
105	    : 0;
106	
107	const followUpDiscountFor = (basePremium: number, isFollowUp: boolean): number =>
108	  isFollowUp ? basePremium * FOLLOW_UP_RATE : 0;
109	
110	const premiumFor = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
111	  const basePremium = basePremiumFor(items);
112	  const surcharges =
113	    itemSurchargesFor(items) + firstInsuranceSurchargeFor(basePremium);
114	  const discounts =
115	    loyaltyDiscountFor(basePremium, customer) +
116	    followUpDiscountFor(basePremium, isFollowUp);
117	  return Math.ceil(basePremium + surcharges - discounts + PROCESSING_FEE);
118	};
119	
120	const insuranceSumFor = (items: Item[]): number =>
121	  items.reduce((sum, { type }) => sum + INSURANCE_VALUE[type], 0);
122	
123	const reimbursableAmountFor = (item: Item, damageAmount: number): number =>
124	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
125	    ? damageAmount * HIGH_ENCHANTMENT_CLAIM_RATE
126	    : damageAmount;
127	
128	const insuredItemFor = (damage: Damage, policy: Policy): Item =>
129	  policy.items.find((item) => item.type === damage.itemType)!;
130	
131	const payoutForDamage = (damage: Damage, policy: Policy): number => {
132	  const reimbursable = reimbursableAmountFor(insuredItemFor(damage, policy), damage.amount);
133	  return Math.max(0, reimbursable - DEDUCTIBLE);
134	};
135	
136	const validateDamages = (damages: Damage[], policy: Policy): void => {
137	  for (const damage of damages) {
138	    if (damage.amount < 0) {
139	      throw new Error(`negative damage amount: ${damage.amount}`);
140	    }
141	  }
142	  const insuredCounts = groupCountsByType(policy.items);
143	  const damageCounts = countBy(damages, (damage) => damage.itemType);
144	  for (const [type, count] of damageCounts) {
145	    if (count > (insuredCounts.get(type) ?? 0)) {
146	      throw new Error(`claim references more ${type} items than insured`);
147	    }
148	  }
149	};
150	
151	const handleClaim = (
152	  { policy: policyIndex, incident }: ClaimStep,
153	  policies: Policy[],
154	): ClaimResult => {
155	  const policy = policies[policyIndex];
156	  validateDamages(incident.damages, policy);
157	  const grossPayout = incident.damages.reduce(
158	    (sum, damage) => sum + payoutForDamage(damage, policy),
159	    0,
160	  );
161	  const payout = Math.floor(Math.min(grossPayout, policy.remainingCap));
162	  policy.remainingCap -= payout;
163	  return { payout, remainingCap: policy.remainingCap };
164	};
165	
166	const openPolicy = (items: Item[]): Policy => ({
167	  items,
168	  remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER,
169	});
170	
171	const handleQuote = (
172	  { items }: QuoteStep,
173	  customer: Customer,
174	  policies: Policy[],
175	): QuoteResult => {
176	  const isFollowUp = policies.length > 0;
177	  policies.push(openPolicy(items));
178	  return { premium: premiumFor(items, customer, isFollowUp) };
179	};
180	
181	export const runScenario = (input: Scenario): ScenarioOutput => {
182	  const policies: Policy[] = [];
183	  const results: StepResult[] = input.steps.map((step) =>
184	    step.op === "quote"
185	      ? handleQuote(step, input.customer, policies)
186	      : handleClaim(step, policies),
187	  );
188	  return { results };
189	};
